module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green
); 
    parameter idle = 2'b00,
              s1_red = 2'b01,
              s2_yellow = 2'b10,
              s3_green = 2'b11;
    reg [1:0] state, nxt_state;
    reg [7:0] cnt, nxt_cnt;
    always@(posedge clk, negedge rst_n) begin
        if (!rst_n) begin
            state <= idle;
            cnt <= 8'd10;
        end else begin
            state <= nxt_state;
            cnt <= nxt_cnt;
        end
    end
    always@(*) begin
        case (state)
            idle: nxt_state = s1_red;
            s1_red: nxt_state = (cnt == 8'd5) ? s3_green : s1_red;
            s2_yellow: nxt_state = (cnt == 8'd5) ? s1_red : s2_yellow;
            s3_green: nxt_state = (cnt == 8'd5) ? s2_yellow : s3_green;
            default: nxt_state = state;
        endcase
    end
    always@(posedge clk, negedge rst_n) begin
        if (!rst_n) begin
            nxt_cnt <= 8'd10;
        end else begin
            if (pass_request && green) begin
                nxt_cnt <= 8'd10;
            end else if (!green && p_green) begin
                nxt_cnt <= 8'd60;
            end else if (!yellow && p_yellow) begin
                nxt_cnt <= 8'd5;
            end else if (!red && p_red) begin
                nxt_cnt <= 8'd10;
            end else begin
                nxt_cnt <= cnt - 8'd1;
            end
        end
    end
    always@(posedge clk, negedge rst_n) begin
        if (!rst_n) begin
            red <= 1'b0;
            yellow <= 1'b0;
            green <= 1'b0;
        end else begin
            red <= p_red;
            yellow <= p_yellow;
            green <= p_green;
        end
    end
endmodule
